(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[1038],{9509:(t,o,e)=>{"use strict";e.r(o),e.d(o,{data:()=>a});const a={key:"v-78ed3e93",path:"/python/data-type/boolean/",title:"Logic Operations",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"ตารางการใช้ Logical Operator",slug:"ตารางการใช้-logical-operator",children:[]},{level:2,title:"Comparison Operator",slug:"comparison-operator",children:[]}],filePathRelative:"python/data-type/boolean/README.md",git:{updatedTime:162676698e4,contributors:[]}}},9909:(t,o,e)=>{"use strict";e.r(o),e.d(o,{default:()=>n});const a=(0,e(6252).uE)('<h1 id="logic-operations" tabindex="-1"><a class="header-anchor" href="#logic-operations" aria-hidden="true">#</a> Logic Operations</h1><p>Logic Operator เป็นการจัดการตัวแปรประเภท boolean เพื่อการจัดการ logic นั่นเอง<br> โดยน้องๆจะได้ใช้งานอีก 1 รอบเมื่อได้เรียน Conditions ครับ</p><p>ตัวอย่าง Logic Operator</p><table><thead><tr><th>Logical Operator</th><th>วิธีการเขียนแบบทั่วไป</th><th>หรือจะเขียนแบบนี้ก็ได้</th></tr></thead><tbody><tr><td>AND</td><td>and</td><td><code>&amp;</code></td></tr><tr><td>OR</td><td>or</td><td>`</td></tr><tr><td>NOT</td><td>not</td><td><code>!</code></td></tr><tr><td>XOR</td><td>xor</td><td><code>^</code></td></tr></tbody></table><p>การเอาโค้ดข้างบนมาเขียนใหม่ จึงได้แบบนี้นั่นเอง</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">if</span> <span class="token punctuation">(</span>first_name <span class="token operator">==</span> <span class="token string">&quot;Kumamon&quot;</span> <span class="token keyword">and</span> age <span class="token operator">==</span> <span class="token number">21</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;My name is Kumamon&quot;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="ตารางการใช้-logical-operator" tabindex="-1"><a class="header-anchor" href="#ตารางการใช้-logical-operator" aria-hidden="true">#</a> ตารางการใช้ Logical Operator</h2><p><img src="http://ds-wordpress.haverford.edu/bitbybit/wp-content/uploads/2012/07/Chapter_3-90.jpg" alt=""><em>ภาพจาก haverford.edu</em></p><p>NOTE : โดย 0 คือค่าเท็จ 1 คือค่าจริง</p><p>จากการสังเกต ก็จะเห็นได้ว่า</p><ul><li><strong>สมการ AND</strong> ตัวแปรทั้งสองต้องเป็น <code>TRUE</code> เพื่อทำให้สมการเป็น <code>TRUE</code></li><li><strong>สมการ OR</strong> ตัวแปรทั้งสองต้องเป็น <code>FALSE</code> เพื่อทำให้สมการเป็น <code>FALSE</code></li><li><strong>สมการ NOT</strong> นั้นจะสลับ logic ไปเป็นอีกฝั่งนึงเลย (เช่น จริงเปลี่ยนไปเป็นเท็จ และ เท็จเปลี่ยนไปเป็นจริง)</li><li><strong>สมการ XOR</strong> นั้นจะเป็น <code>TRUE</code> เมื่อสมการใดซักอันหนึ่งเป็น <code>TRUE</code> แต่หากเป็น <code>TRUE</code> หรือ <code>FALSE</code> ทั้งคู่ ค่าที่ออกมาจะเป็น <code>FALSE</code></li></ul><h2 id="comparison-operator" tabindex="-1"><a class="header-anchor" href="#comparison-operator" aria-hidden="true">#</a> Comparison Operator</h2><table><thead><tr><th><strong>==</strong></th><th><strong>!=</strong></th><th><strong>&lt;</strong></th><th><strong>&lt;=</strong></th><th><strong>&gt;</strong></th><th><strong>&gt;=</strong></th></tr></thead><tbody><tr><td>มีค่าเท่ากับ</td><td>ค่าไม่เท่ากับ</td><td>น้อยกว่า</td><td>น้อยกว่า หรือ เท่ากับ</td><td>มากกว่า</td><td>มากกว่า หรือ เท่ากับ</td></tr></tbody></table>',13),n={render:function(t,o){return a}}}}]);